CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE IF NOT EXISTS pacientes_ris(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),his_patient_id UUID UNIQUE,tipo_documento VARCHAR(10),numero_documento VARCHAR(30),primer_nombre VARCHAR(80),segundo_nombre VARCHAR(80),primer_apellido VARCHAR(80),segundo_apellido VARCHAR(80),fecha_nacimiento DATE,genero VARCHAR(10),created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS modalidades(id SERIAL PRIMARY KEY,codigo VARCHAR(20) UNIQUE NOT NULL,nombre VARCHAR(100),activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS estados_estudio_radiologia(id SERIAL PRIMARY KEY,codigo VARCHAR(40) UNIQUE NOT NULL,nombre VARCHAR(100),activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS equipos_radiologia(id SERIAL PRIMARY KEY,nombre VARCHAR(100),modalidad_id INTEGER REFERENCES modalidades(id),activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS salas_radiologia(id SERIAL PRIMARY KEY,nombre VARCHAR(100),equipo_id INTEGER REFERENCES equipos_radiologia(id),activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS ordenes_radiologia(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),his_order_id UUID UNIQUE,numero_orden_his VARCHAR(80),paciente_id UUID REFERENCES pacientes_ris(id),prioridad VARCHAR(30),observaciones TEXT,payload_his JSONB,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS estudios_radiologicos(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),orden_id UUID REFERENCES ordenes_radiologia(id),paciente_id UUID REFERENCES pacientes_ris(id),modalidad_id INTEGER REFERENCES modalidades(id),estado_id INTEGER REFERENCES estados_estudio_radiologia(id),descripcion TEXT,codigo_cups VARCHAR(30),created_at TIMESTAMP DEFAULT NOW(),updated_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS agenda_radiologia(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),estudio_id UUID REFERENCES estudios_radiologicos(id),sala_id INTEGER REFERENCES salas_radiologia(id),fecha_hora TIMESTAMP,estado VARCHAR(30) DEFAULT 'PROGRAMADA');
CREATE TABLE IF NOT EXISTS estudios_pacs(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),estudio_id UUID REFERENCES estudios_radiologicos(id),orthanc_study_id TEXT,orthanc_series_id TEXT,orthanc_instance_id TEXT,url_visualizacion TEXT,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS series_dicom(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),estudio_pacs_id UUID REFERENCES estudios_pacs(id),orthanc_series_id TEXT,descripcion TEXT);
CREATE TABLE IF NOT EXISTS informes_radiologia(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),estudio_id UUID REFERENCES estudios_radiologicos(id),pregunta_clinica TEXT,tecnica_usada TEXT,hallazgos TEXT,conclusion TEXT,estudio_relacionado_id UUID,estado VARCHAR(30) DEFAULT 'BORRADOR',validado_por VARCHAR(150),validado_at TIMESTAMP,enviado_his BOOLEAN DEFAULT FALSE,enviado_his_at TIMESTAMP,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS historial_estado_estudio(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),estudio_id UUID REFERENCES estudios_radiologicos(id),estado_id INTEGER REFERENCES estados_estudio_radiologia(id),observacion TEXT,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS integracion_his_ris(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),his_order_id UUID,ris_order_id UUID,evento VARCHAR(80),estado VARCHAR(30),payload_json JSONB,response_json JSONB,created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS ris_menus(id SERIAL PRIMARY KEY,texto VARCHAR(80),ruta VARCHAR(120),icono_bootstrap VARCHAR(80),permiso_requerido VARCHAR(100),orden INTEGER DEFAULT 0,activo BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS auditoria_ris(id BIGSERIAL PRIMARY KEY,usuario_id UUID,usuario_email VARCHAR(150),accion VARCHAR(100),entidad VARCHAR(80),entidad_id UUID,ip VARCHAR(80),user_agent TEXT,detalle TEXT,created_at TIMESTAMP DEFAULT NOW());
